    {
      "content": "若 $C_n^2 = 15$，则下列选项中，$A_n^2$ 的值为（ ）",
      "item_type": "choice",
      "options": [
        {
          "label": "A",
          "text": "15"
        },
        {
          "label": "B",
          "text": "25"
