        {
          "label": "C",
          "text": "30"
        },
        {
          "label": "D",
          "text": "60"
        }
      ],
      "answer": "C",
      "solution_text": "$A_n^2 = C_n^2 A_2^2 = 15 \\times 2 = 30$",
      "difficulty": 3,
      "kp_hints": [
        "排列数与组合数的关系",
        "排列数公式",
        "组合数公式"
      ],
